function initFolders(keys: string[]) {
    const dirTable: { [name: string]: number } = {};
    for (let i = 0; i < keys.length; i++) {
        if (keys[i].startsWith("< f >")) {
            dirTable[keys[i].slice(5)] = i;
        }
        if (keys[i].startsWith("< f />")) {
            const name = keys[i].slice(6);
            const begin = dirTable[name];
            keys.splice(i--, 1);
            const count = i - begin;
            keys[begin] = `< f >${name.split("::")[0]}::${count}::${(Math.floor(Math.random() * 2176782336)).toString(36)}::+`;
        }
    }
    return keys;
}
